// Lightweight Supabase health check
// Calls the Supabase REST health endpoint to keep the free-tier project active.
// Supabase pauses inactive free projects after 7 days — this runs every 5 days.

const supabaseUrl = $env.STORYLOFT_SUPABASE_URL;
const supabaseKey = $env.STORYLOFT_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseKey) {
  throw new Error('STORYLOFT_SUPABASE_URL or STORYLOFT_SUPABASE_ANON_KEY not set in n8n environment variables.');
}

return {
  json: {
    url: `${supabaseUrl}/rest/v1/`,
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`
    },
    supabaseUrl,
    triggeredAt: new Date().toISOString()
  }
};

const result = $input.first().json;
const triggeredAt = $('Build Request').first().json.triggeredAt;

return {
  json: {
    status: 'ok',
    message: 'Supabase keep-alive ping succeeded',
    triggeredAt,
    completedAt: new Date().toISOString(),
    httpStatus: result.$response?.statusCode ?? 'unknown'
  }
};

const error = $input.first().json;
const triggeredAt = $('Build Request').first().json.triggeredAt;

// Log the failure — extend this node to send a Slack/email alert if desired
console.error('StoryLoft Supabase keep-alive FAILED:', JSON.stringify(error));

return {
  json: {
    status: 'error',
    message: 'Supabase keep-alive ping failed',
    triggeredAt,
    failedAt: new Date().toISOString(),
    error: error.message ?? JSON.stringify(error)
  }
};
